  1→import React, { useCallback, useEffect, useState } from "react";
  2→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  3→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  4→import { HistoryPlugin } from "@lexical/react/LexicalHistoryPlugin";
  5→import { OnChangePlugin } from "@lexical/react/LexicalOnChangePlugin";
  6→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
  7→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  8→import ImagePlugin from "./nodes/Plugins/ImagePlugin";
  9→
 10→
 11→import ToolBar from "./Toolbar";
 12→
 13→import { saveJournal } from "../../../../API/Api";
 14→import { useAuth } from "../../../Context/useAuth";
 15→import { useQuery, useQueryClient } from '@tanstack/react-query';
 16→
 17→import { BarLoader } from "react-spinners";
 18→import { $getRoot } from "lexical";
 19→
 20→
 21→class ErrorBoundary extends React.Component {
 22→  state = { error: null };
 23→  static getDerivedStateFromError(error) {
 24→    return { error };
 25→  }
 26→  render() {
 27→    if (this.state.error) {
 28→      return <div>Error: {this.state.error.message}</div>;
 29→    }
 30→    return this.props.children;
 31→  }
 32→}
 33→
 34→/* theme for mapping css classes to lexical rols */
 35→const theme = {
 36→    paragraph: 'editor-paragraph',
 37→    heading: 'editor-heading',
 38→}
 39→
 40→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, onSwitchToCanvas, promptId = null}) => {
 41→    const [editor] = useLexicalComposerContext();
 42→    const [editorState, setEditorState] = useState(null);
 43→    const [hasContent, setHasContent] = useState(false);
 44→    const [isSending, setIsSending] = useState(false);
 45→
 46→    const {session, user} = useAuth();
 47→
 48→    const queryClient = useQueryClient();
 49→
 50→    const handleClickSave = async(e, title) =>{
 51→        e.stopPropagation();
 52→        setIsSending(true)
 53→        try {
 54→            const formdata = new FormData();
 55→            if(title && editorState){
 56→                formdata.append('title', title)
 57→                formdata.append('content', editorState)
 58→            }
 59→            if(promptId){
 60→                formdata.append('prompt_id', promptId);
 61→            }
 62→            const saveData = await saveJournal(session?.access_token, formdata)
 63→
 64→            if(saveData){
 65→                // console.log(saveData)
 66→                queryClient.invalidateQueries({queryKey: ['journals']});
 67→                queryClient.invalidateQueries({queryKey: ['userJournals', user?.userData?.[0].id]})
 68→                queryClient.invalidateQueries({queryKey: ['streak', user?.userData?.[0]?.id]});
 69→            }
 70→
 71→            setIsSending(false)
 72→        } catch (error) {
 73→            console.error("Error saving journal:", error);
 74→        }finally {
 75→            setIsSending(false)
 76→            setHasContent(false)
 77→            onCloseOnSave();
 78→            addUploadImagesPath([])
 79→        }
 80→
 81→    }
 82→
 83→    const onchange = useCallback((state) => {
 84→        const jsonb = JSON.stringify(state.toJSON());
 85→        setEditorState(jsonb)
 86→
 87→        state.read(() => {
 88→            const root = $getRoot();
 89→
 90→            const children = root.getChildren();
 91→
 92→            const hasEnoughParagraphNodes = children.length > 1
 93→            const hasParargraphSize = children[0]?.__size > 0
 94→
 95→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
 96→            setHasContent(hasContent);
 97→
 98→            // Calculate word count
 99→            const text = root.getTextContent().trim();
100→            const words = text ? text.split(/\s+/).length : 0;
101→            setWordCount(words);
102→        })
103→    }, [setWordCount])
104→
105→    return(
106→        <>
107→        {/* Toolbar above content */}
108→        <div className="toolbar-wrapper">
109→            <ToolBar addUploadedImagePath={addUploadImagesPath} onSwitchToCanvas={onSwitchToCanvas}/>
110→        </div>
111→
112→        {/* Bar loader directly under toolbar */}
113→        <div className="editor-loader-wrapper">
114→            {isSending && (
115→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
116→            )}
117→        </div>
118→
119→        {/* Editor content area */}
120→        <div className="editor-shell">
121→            <RichTextPlugin
122→            contentEditable={
123→            <ContentEditable
124→            className="editor-input"
125→            aria-placeholder="Write your thoughts here..."
126→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
127→            }
128→            ErrorBoundary={LexicalErrorBoundary}
129→            />
130→
131→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
132→            <HistoryPlugin/>
133→            <OnChangePlugin onChange={onchange}/>
134→
135→        </div>
136→
137→        {/* Footer: word count + save */}
138→        <div className='editor-footer'>
139→            <span className="editor-word-count">
140→                {wordCount} {wordCount === 1 ? 'word' : 'words'}
141→            </span>
142→            <button disabled={!title || !hasContent || isSending} onClick={(e) =>handleClickSave(e, title)} className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}>
143→                Share
144→            </button>
145→        </div>
146→        </>
147→    )
148→}
149→
150→export default EditorInner;
