132→    viewportWidth,
133→    viewportHeight,
134→    stageWidth,
135→    stageHeight,
136→    fitScale = 1,
137→    fitOffsetX = 0,
138→    fitOffsetY = 0,
139→    viewport = {scale: 1, x: 0, y: 0},
140→    gridEnabled = false,
141→    theme = "light",
142→    doodles = [],
143→    isDrawing = false,
144→    currentDoodlePoints = [],
