228→                        ))}
229→                        stroke={doodle.color || DEFAULT_DOODLE_COLOR}
230→                        strokeWidth={(Number(doodle.size) || 2.8) * doodleStrokeScale}
231→                        lineCap="round"
232→                        lineJoin="round"
233→                        tension={0.35}
234→                    />
235→                ))}
